#!/usr/bin/env python3
"""
To trim or not to trim, that is the question which
predict_trimming.py
answers

A standalone CLI tool to predict the optimal RNA-Seq trimming strategy 
using a pre-trained RandomForest model from Leave-One-Sample-Out biological concordance data from about 1000 SRR samples.

This file is a standalone package. It contains the embedded FastQC parser 
and the base64-encoded Random Forest model.
"""

import sys
import os
import pathlib
import warnings
import json
import argparse
import base64
import io
from collections import defaultdict
warnings.filterwarnings("ignore")

import pandas as pd
import numpy as np
import joblib

# ==============================================================================
# EMBEDDED FASTQC PARSER
# ==============================================================================
def parse_range_width(token: str) -> int:
    token = token.strip()
    if "-" in token:
        a, b = token.split("-", 1)
        return int(b) - int(a) + 1
    return 1


def parse_range_midpoint(token: str) -> float:
    token = token.strip()
    if "-" in token:
        a, b = token.split("-", 1)
        return (int(a) + int(b)) / 2
    return float(token)


def parse_fastqc_data(path: Path) -> dict[str, float | str]:
    lines = path.read_text(encoding="utf-8", errors="replace").splitlines()

    basic = {}
    sections: dict[str, list[list[str]]] = defaultdict(list)
    current = None
    for line in lines:
        if line.startswith(">>"):
            if line.startswith(">>END_MODULE"):
                current = None
                continue
            current = line[2:].split("\t", 1)[0]
            continue
        if current == "Basic Statistics":
            if line.startswith("#") or not line.strip():
                continue
            parts = line.split("\t")
            if len(parts) >= 2:
                basic[parts[0]] = parts[1]
        elif current:
            if line.startswith("#") or not line.strip():
                continue
            sections[current].append(line.split("\t"))

    total_sequences = float(basic.get("Total Sequences", "0") or 0)
    gc_content = float(basic.get("%GC", "0") or 0)

    # Per-base quality features
    quality_rows = sections.get("Per base sequence quality", [])
    q_weight = 0
    q_mean_sum = q_median_sum = 0.0
    q_max = float("-inf")
    q_min = float("inf")
    q20_weight = q30_weight = 0
    quality_profile = []
    for row in quality_rows:
        width = parse_range_width(row[0])
        mean = float(row[1])
        median = float(row[2])
        low_q = float(row[3])
        high_q = float(row[4])
        q_weight += width
        q_mean_sum += mean * width
        q_median_sum += median * width
        q_max = max(q_max, high_q)
        q_min = min(q_min, low_q)
        if mean < 20:
            q20_weight += width
        if mean < 30:
            q30_weight += width
        quality_profile.extend([mean] * width)

    q_mean = q_mean_sum / q_weight if q_weight else None
    q_median = q_median_sum / q_weight if q_weight else None
    frac_below_q20 = q20_weight / q_weight if q_weight else None
    frac_below_q30 = q30_weight / q_weight if q_weight else None
    if quality_profile:
        head = quality_profile[: min(10, len(quality_profile))]
        tail = quality_profile[-min(10, len(quality_profile)) :]
        tail_quality_decay = (sum(head) / len(head)) - (sum(tail) / len(tail))
    else:
        tail_quality_decay = None

    # Read length distribution
    length_rows = sections.get("Sequence Length Distribution", [])
    total_len_count = 0
    weighted_len_sum = 0.0
    lengths = []
    length_min = float("inf")
    length_max = float("-inf")
    for row in length_rows:
        length = parse_range_midpoint(row[0])
        count = float(row[1])
        total_len_count += count
        weighted_len_sum += length * count
        lengths.append((length, count))
        length_min = min(length_min, length)
        length_max = max(length_max, length)
    if lengths and total_len_count:
        read_length_mean = weighted_len_sum / total_len_count
        half = total_len_count / 2
        cum = 0.0
        read_length_median = read_length_mean
        for length, count in sorted(lengths):
            cum += count
            if cum >= half:
                read_length_median = length
                break
    else:
        read_length_mean = read_length_median = None
        length_min = length_max = None

    # Adapter content
    adapter_rows = sections.get("Adapter Content", [])
    adapter_rate = 0.0
    for row in adapter_rows:
        vals = [float(v) for v in row[1:] if v not in {"", "NA"}]
        if vals:
            adapter_rate = max(adapter_rate, max(vals))

    # Duplication
    dup_rows = sections.get("Sequence Duplication Levels", [])
    duplication_rate = None
    for row in dup_rows:
        if row[0] == "#Total Deduplicated Percentage" and len(row) > 1:
            duplication_rate = 100.0 - float(row[1])
            break
    if duplication_rate is None:
        for raw in lines:
            if raw.startswith("#Total Deduplicated Percentage"):
                parts = raw.split("\t")
                if len(parts) > 1:
                    duplication_rate = 100.0 - float(parts[1])
                break

    # N content
    n_rows = sections.get("Per base N content", [])
    n_weight = 0
    n_sum = 0.0
    for row in n_rows:
        width = parse_range_width(row[0])
        val = float(row[1])
        n_weight += width
        n_sum += val * width
    n_content = n_sum / n_weight if n_weight else 0.0

    return {
        "sequence_depth": total_sequences,
        "Q_mean": q_mean,
        "Q_median": q_median,
        "Q_max": q_max if q_weight else None,
        "Q_min": q_min if q_weight else None,
        "read_length_mean": read_length_mean,
        "read_length_median": read_length_median,
        "read_length_max": length_max,
        "read_length_min": length_min,
        "frac_below_q20": frac_below_q20,
        "frac_below_q30": frac_below_q30,
        "tail_quality_decay": tail_quality_decay,
        "adapter_rate": adapter_rate,
        "duplication_rate": duplication_rate,
        "n_content": n_content,
        "gc_content": gc_content,
        "gc_deviation": abs(gc_content - 50.0),
    }



# ==============================================================================
# EMBEDDED MODEL BINARY
# ==============================================================================
MODEL_B64 = ""

def load_embedded_model():
    model_bytes = base64.b64decode(MODEL_B64)
    buffer = io.BytesIO(model_bytes)
    return joblib.load(buffer)

def main():
    help_text = """
Description:
  Predict the mathematically optimal RNA-Seq trimming stringency directly from 
  raw FastQC data using a Random Forest model trained on biological concordance.

Usage Examples:
  1. Standard Pipeline Mode (Outputs pure JSON):
     python3 predict_trimming.py /path/to/fastqc_data.txt
     
  2. Human-Readable Mode (Outputs detailed explanation):
     python3 predict_trimming.py /path/to/fastqc_data.txt --explain
    """
    parser = argparse.ArgumentParser(
        description="Predict optimal RNA-Seq trimming strategy from FastQC data.",
        epilog=help_text,
        formatter_class=argparse.RawTextHelpFormatter
    )
    parser.add_argument("fastqc_file", type=str, help="Path to the fastqc_data.txt file.")
    parser.add_argument("--explain", action="store_true", help="Print intricate details and interpretation of the analysis instead of JSON.")
    args = parser.parse_args()

    fastqc_file = pathlib.Path(args.fastqc_file)
    if not fastqc_file.exists():
        if args.explain:
            print(f"Error: File '{fastqc_file}' not found.")
        else:
            print(json.dumps({"error": f"File '{fastqc_file}' not found."}))
        sys.exit(1)

    if args.explain:
        print(f"Parsing FastQC report: {fastqc_file.name} ...")
        
    try:
        parsed_data = parse_fastqc_data(fastqc_file)
    except Exception as e:
        if args.explain:
            print(f"Failed to parse FastQC data: {e}")
        else:
            print(json.dumps({"error": f"Failed to parse FastQC data: {e}"}))
        sys.exit(1)

    if args.explain:
        print("Loading embedded predictive QC model...")
        
    model_data = load_embedded_model()
    rf = model_data["model"]
    features = model_data["features"]

    # Convert to DataFrame
    df = pd.DataFrame([parsed_data])
    
    # Handle missing values by coercing to numeric and filling with 0
    for f in features:
        if f not in df.columns:
            df[f] = 0.0
        df[f] = pd.to_numeric(df[f], errors="coerce").fillna(0.0)

    X = df[features].values

    # Predict
    prediction = str(rf.predict(X)[0])
    probs = rf.predict_proba(X)[0]
    
    # Sort probabilities descending
    class_probs = list(zip(rf.classes_, probs))
    class_probs.sort(key=lambda x: x[1], reverse=True)

    if not args.explain:
        # Strict JSON output
        out_dict = {
            "prediction": prediction,
            "confidence": {str(c): float(p) for c, p in class_probs}
        }
        print(json.dumps(out_dict, indent=2))
    else:
        # Verbose Human-readable output
        print("=====================================================")
        print(f" PREDICTED OPTIMAL TRIMMING STRINGENCY:  {prediction} ")
        print("=====================================================")
        print("Confidence Distribution:")
        for c, p in class_probs:
            print(f"  {c:>4}:  {p:>6.2%}")
            
        print("\nInterpretation:")
        if prediction == "U":
            print("The model predicts that this sample is of high quality or that trimming ")
            print("will provide little to no biological benefit and risks introducing alignment bias. ")
            print("Recommendation: Proceed with Untrimmed (U) reads.")
        elif prediction == "NA":
            print("The model predicts that this sample's quality profile is highly anomalous or poor.")
            print("It has a high likelihood of catastrophic failure in downstream biological concordance.")
            print("Recommendation: Investigate raw data manually before proceeding.")
        else:
            print(f"The model detected QC artifacts that may negatively impact downstream pathway ")
            print(f"concordance. Trimming using method '{prediction}' is recommended to ")
            print("rescue biological signal.")

if __name__ == "__main__":
    main()
